397	func CopyModel(src, dst model.Name) error {
398		if !dst.IsFullyQualified() {
399			return model.Unqualified(dst)
400		}
401		if !src.IsFullyQualified() {
402			return model.Unqualified(src)
403		}
404	
405		if src.Filepath() == dst.Filepath() {
406			return nil
407		}
408	
409		manifests, err := manifest.Path()
410		if err != nil {
411			return err
412		}
413	
414		dstpath := filepath.Join(manifests, dst.Filepath())
415		if err := os.MkdirAll(filepath.Dir(dstpath), 0o755); err != nil {
416			return err
417		}
418	
419		srcpath := filepath.Join(manifests, src.Filepath())
420		srcfile, err := os.Open(srcpath)
421		if err != nil {
422			return err
423		}
424		defer srcfile.Close()
425	
426		dstfile, err := os.Create(dstpath)
427		if err != nil {
428			return err
429		}
430		defer dstfile.Close()
431	
432		_, err = io.Copy(dstfile, srcfile)
433		return err
434	}
