511	func PushModel(ctx context.Context, name string, regOpts *registryOptions, fn func(api.ProgressResponse)) error {
512		n := model.ParseName(name)
513		fn(api.ProgressResponse{Status: "retrieving manifest"})
514	
515		if n.ProtocolScheme == "http" && !regOpts.Insecure {
516			return errInsecureProtocol
517		}
518	
519		mf, err := manifest.ParseNamedManifest(n)
520		if err != nil {
521			fn(api.ProgressResponse{Status: "couldn't retrieve manifest"})
522			return err
523		}
524	
525		var layers []manifest.Layer
526		layers = append(layers, mf.Layers...)
527		if mf.Config.Digest != "" {
528			layers = append(layers, mf.Config)
529		}
530	
531		// Use fast transfer for models with tensor layers (many small blobs)
532		if hasTensorLayers(layers) {
533			// Read raw manifest JSON to preserve tensor metadata fields
534			manifestPath, err := manifest.PathForName(n)
535			if err != nil {
536				return err
537			}
538			manifestJSON, err := os.ReadFile(manifestPath)
539			if err != nil {
540				return err
541			}
542			if err := pushWithTransfer(ctx, n, layers, manifestJSON, regOpts, fn); err != nil {
543				return err
544			}
545			fn(api.ProgressResponse{Status: "success"})
546			return nil
547		}
548	
549		for _, layer := range layers {
550			if err := uploadBlob(ctx, n, layer, regOpts, fn); err != nil {
551				slog.Info(fmt.Sprintf("error uploading blob: %v", err))
552				return err
553			}
554		}
555	
556		fn(api.ProgressResponse{Status: "pushing manifest"})
557		requestURL := n.BaseURL()
558		requestURL = requestURL.JoinPath("v2", n.DisplayNamespaceModel(), "manifests", n.Tag)
559	
560		manifestJSON, err := json.Marshal(mf)
561		if err != nil {
562			return err
563		}
564	
565		headers := make(http.Header)
566		headers.Set("Content-Type", "application/vnd.docker.distribution.manifest.v2+json")
567		resp, err := makeRequestWithRetry(ctx, http.MethodPut, requestURL, headers, bytes.NewReader(manifestJSON), regOpts)
568		if err != nil {
569			return err
570		}
571		defer resp.Body.Close()
572	
573		fn(api.ProgressResponse{Status: "success"})
574	
575		return nil
576	}
