578	func PullModel(ctx context.Context, name string, regOpts *registryOptions, fn func(api.ProgressResponse)) error {
579		n := model.ParseName(name)
580	
581		// build deleteMap to prune unused layers
582		deleteMap := make(map[string]struct{})
583		existingMf, err := manifest.ParseNamedManifest(n)
584		if errors.Is(err, os.ErrNotExist) {
585			// noop
586		} else if err != nil {
587			slog.Warn("pulling model with bad existing manifest", "name", name, "error", err)
588		} else {
589			for _, l := range existingMf.Layers {
590				deleteMap[l.Digest] = struct{}{}
591			}
592			if existingMf.Config.Digest != "" {
593				deleteMap[existingMf.Config.Digest] = struct{}{}
594			}
595		}
596	
597		if n.ProtocolScheme == "http" && !regOpts.Insecure {
598			return errInsecureProtocol
599		}
600	
601		fn(api.ProgressResponse{Status: "pulling manifest"})
602	
603		mf, manifestData, err := pullModelManifest(ctx, n, regOpts)
604		if err != nil {
605			return fmt.Errorf("pull model manifest: %s", err)
606		}
607	
608		var layers []manifest.Layer
609		layers = append(layers, mf.Layers...)
610		if mf.Config.Digest != "" {
611			layers = append(layers, mf.Config)
612		}
613	
614		// Use fast transfer for models with tensor layers (many small blobs)
615		if hasTensorLayers(layers) {
616			if err := pullWithTransfer(ctx, n, layers, manifestData, regOpts, fn); err != nil {
617				return err
618			}
619			fn(api.ProgressResponse{Status: "success"})
620			return nil
621		}
622	
623		skipVerify := make(map[string]bool)
624		for _, layer := range layers {
625			cacheHit, err := downloadBlob(ctx, downloadOpts{
626				n:       n,
627				digest:  layer.Digest,
628				regOpts: regOpts,
629				fn:      fn,
630			})
631			if err != nil {
632				return err
633			}
634			skipVerify[layer.Digest] = cacheHit
635			delete(deleteMap, layer.Digest)
636		}
637	
638		fn(api.ProgressResponse{Status: "verifying sha256 digest"})
639		for _, layer := range layers {
640			if skipVerify[layer.Digest] {
641				continue
642			}
643			if err := verifyBlob(layer.Digest); err != nil {
644				if errors.Is(err, errDigestMismatch) {
645					fp, err := manifest.BlobsPath(layer.Digest)
646					if err != nil {
647						return err
648					}
649					if err := os.Remove(fp); err != nil {
650						slog.Info(fmt.Sprintf("couldn't remove file with digest mismatch '%s': %v", fp, err))
651					}
652				}
653				return err
654			}
655		}
656	
657		for _, layer := range layers {
658			delete(deleteMap, layer.Digest)
659		}
660		delete(deleteMap, mf.Config.Digest)
661	
662		fn(api.ProgressResponse{Status: "writing manifest"})
663	
664		fp, err := manifest.PathForName(n)
665		if err != nil {
666			return err
667		}
668		if err := os.MkdirAll(filepath.Dir(fp), 0o755); err != nil {
669			return err
670		}
671	
672		err = os.WriteFile(fp, manifestData, 0o644)
673		if err != nil {
674			slog.Info(fmt.Sprintf("couldn't write to %s", fp))
675			return err
676		}
677	
678		slog.Debug("manifest written", "path", fp, "sha256", fmt.Sprintf("%x", sha256.Sum256(manifestData)), "size", len(manifestData))
679	
680		if !envconfig.NoPrune() && len(deleteMap) > 0 {
681			fn(api.ProgressResponse{Status: "removing unused layers"})
682			if err := deleteUnusedLayers(deleteMap); err != nil {
683				fn(api.ProgressResponse{Status: fmt.Sprintf("couldn't remove unused layers: %v", err)})
684			}
685		}
686	
687		fn(api.ProgressResponse{Status: "success"})
688	
689		return nil
690	}
