870	var errUnauthorized = errors.New("unauthorized: access denied")
871	
872	func makeRequestWithRetry(ctx context.Context, method string, requestURL *url.URL, headers http.Header, body io.ReadSeeker, regOpts *registryOptions) (*http.Response, error) {
873		for range 2 {
874			resp, err := makeRequest(ctx, method, requestURL, headers, body, regOpts)
875			if err != nil {
876				if !errors.Is(err, context.Canceled) {
877					slog.Info(fmt.Sprintf("request failed: %v", err))
878				}
879	
880				return nil, err
881			}
882	
883			switch {
884			case resp.StatusCode == http.StatusUnauthorized:
885				resp.Body.Close()
886	
887				// Handle authentication error with one retry
888				challenge := parseRegistryChallenge(resp.Header.Get("www-authenticate"))
889				token, err := getAuthorizationToken(ctx, challenge, requestURL.Host)
890				if err != nil {
891					return nil, err
892				}
893				regOpts.Token = token
894				if body != nil {
895					_, err = body.Seek(0, io.SeekStart)
896					if err != nil {
897						return nil, err
898					}
899				}
900			case resp.StatusCode == http.StatusNotFound:
901				resp.Body.Close()
902				return nil, os.ErrNotExist
903			case resp.StatusCode >= http.StatusBadRequest:
904				defer resp.Body.Close()
905				responseBody, err := io.ReadAll(resp.Body)
906				if err != nil {
907					return nil, fmt.Errorf("%d: %s", resp.StatusCode, err)
908				}
909				return nil, fmt.Errorf("%d: %s", resp.StatusCode, responseBody)
910			default:
911				return resp, nil
912			}
913		}
914	
915		return nil, errUnauthorized
916	}
