918	// testMakeRequestDialContext specifies the dial function for the http client in
919	// makeRequest. It can be used to resolve hosts in model names to local
920	// addresses for testing. For example, the model name ("example.com/my/model")
921	// can be directed to push/pull from "127.0.0.1:1234".
922	//
923	// This is not safe to set across goroutines. It should be set in
924	// the main test goroutine, and not by tests marked to run in parallel with
925	// t.Parallel().
926	//
927	// It should be cleared after use, otherwise it will affect other tests.
928	//
929	// Ideally we would have some set this up the stack, but the code is not
930	// structured in a way that makes this easy, so this will have to do for now.
931	var testMakeRequestDialContext func(ctx context.Context, network, addr string) (net.Conn, error)
932	
933	func makeRequest(ctx context.Context, method string, requestURL *url.URL, headers http.Header, body io.Reader, regOpts *registryOptions) (*http.Response, error) {
934		if requestURL.Scheme != "http" && regOpts != nil && regOpts.Insecure {
935			requestURL.Scheme = "http"
936		}
937	
938		req, err := http.NewRequestWithContext(ctx, method, requestURL.String(), body)
939		if err != nil {
940			return nil, err
941		}
942	
943		if headers != nil {
944			req.Header = headers
945		}
946	
947		if regOpts != nil {
948			if regOpts.Token != "" {
949				req.Header.Set("Authorization", "Bearer "+regOpts.Token)
950			} else if regOpts.Username != "" && regOpts.Password != "" {
951				req.SetBasicAuth(regOpts.Username, regOpts.Password)
952			}
953		}
954	
955		req.Header.Set("User-Agent", fmt.Sprintf("ollama/%s (%s %s) Go/%s", version.Version, runtime.GOARCH, runtime.GOOS, runtime.Version()))
956	
957		if s := req.Header.Get("Content-Length"); s != "" {
958			contentLength, err := strconv.ParseInt(s, 10, 64)
959			if err != nil {
960				return nil, err
961			}
962	
963			req.ContentLength = contentLength
964		}
965	
966		c := &http.Client{
967			CheckRedirect: regOpts.CheckRedirect,
968		}
969		if testMakeRequestDialContext != nil {
970			tr := http.DefaultTransport.(*http.Transport).Clone()
971			tr.DialContext = testMakeRequestDialContext
972			c.Transport = tr
973		}
974		return c.Do(req)
975	}
