977	func getValue(header, key string) string {
978		startIdx := strings.Index(header, key+"=")
979		if startIdx == -1 {
980			return ""
981		}
982	
983		// Move the index to the starting quote after the key.
984		startIdx += len(key) + 2
985		endIdx := startIdx
986	
987		for endIdx < len(header) {
988			if header[endIdx] == '"' {
989				if endIdx+1 < len(header) && header[endIdx+1] != ',' { // If the next character isn't a comma, continue
990					endIdx++
