310	
311		bars := make(map[string]*progress.Bar)
312		fn := func(resp api.ProgressResponse) error {
313			if resp.Digest != "" {
314				bar, ok := bars[resp.Digest]
315				if !ok {
316					msg := resp.Status
317					if msg == "" {
318						msg = fmt.Sprintf("pulling %s...", resp.Digest[7:19])
319					}
320					bar = progress.NewBar(msg, resp.Total, resp.Completed)
321					bars[resp.Digest] = bar
322					p.Add(resp.Digest, bar)
323				}
324	
325				bar.Set(resp.Completed)
326			} else if status != resp.Status {
327				spinner.Stop()
328	
329				status = resp.Status
330				spinner = progress.NewSpinner(status)
331				p.Add(status, spinner)
