54	func resolvePath(name string) string {
55		// look in the app bundle first
56		if exe, _ := os.Executable(); exe != "" {
57			var dir string
58			if runtime.GOOS == "windows" {
59				dir = filepath.Dir(exe)
60			} else {
61				dir = filepath.Join(filepath.Dir(exe), "..", "Resources")
62			}
63			if _, err := os.Stat(filepath.Join(dir, name)); err == nil {
64				return filepath.Join(dir, name)
65			}
66		}
67	
68		// check the development dist path
69		for _, path := range []string{
70			filepath.Join("dist", runtime.GOOS, name),
71			filepath.Join("dist", runtime.GOOS+"-"+runtime.GOARCH, name),
72		} {
73			if _, err := os.Stat(path); err == nil {
74				return path
75			}
76		}
77	
78		// fallback to system path
79		if p, _ := exec.LookPath(name); p != "" {
80			return p
81		}
82	
83		return name
84	}
