86	// cleanup checks the pid file for a running ollama process
87	// and shuts it down gracefully if it is running
88	func cleanup() error {
89		data, err := os.ReadFile(pidFile)
90		if err != nil {
91			if os.IsNotExist(err) {
92				return nil
93			}
94			return err
95		}
96		defer os.Remove(pidFile)
97	
98		pid, err := strconv.Atoi(strings.TrimSpace(string(data)))
99		if err != nil {
100			return err
101		}
102	
103		proc, err := os.FindProcess(pid)
104		if err != nil {
105			return nil
106		}
107	
108		ok, err := terminated(pid)
109		if err != nil {
110			slog.Debug("cleanup: error checking if terminated", "pid", pid, "err", err)
111		}
112		if ok {
113			return nil
114		}
115	
116		slog.Info("detected previous ollama process, cleaning up", "pid", pid)
117		return stop(proc)
118	}
