120	// stop waits for a process with the provided pid to exit by polling
121	// `terminated(pid)`. If the process has not exited within 5 seconds, it logs a
122	// warning and kills the process.
123	func stop(proc *os.Process) error {
124		if proc == nil {
125			return nil
126		}
127	
128		if err := terminate(proc); err != nil {
129			slog.Warn("graceful terminate failed, killing", "err", err)
130			return proc.Kill()
131		}
132	
133		deadline := time.NewTimer(5 * time.Second)
134		defer deadline.Stop()
135	
136		for {
137			select {
138			case <-deadline.C:
139				slog.Warn("timeout waiting for graceful shutdown; killing", "pid", proc.Pid)
140				return proc.Kill()
141			default:
142				ok, err := terminated(proc.Pid)
143				if err != nil {
144					slog.Error("error checking if ollama process is terminated", "err", err)
145					return err
146				}
147				if ok {
148					return nil
149				}
150				time.Sleep(10 * time.Millisecond)
151			}
152		}
153	}
