155	func (s *Server) Run(ctx context.Context) error {
156		l, err := openRotatingLog()
157		if err != nil {
158			return err
159		}
160		s.log = l
161		defer s.log.Close()
162	
163		if err := cleanup(); err != nil {
164			slog.Warn("failed to cleanup previous ollama process", "err", err)
165		}
166	
167		reaped := false
168		for ctx.Err() == nil {
169			select {
170			case <-ctx.Done():
171				return ctx.Err()
172			case <-time.After(restartDelay):
173			}
174	
175			cmd, err := s.cmd(ctx)
176			if err != nil {
177				return err
178			}
179	
180			if err := cmd.Start(); err != nil {
181				return err
182			}
183	
184			err = os.WriteFile(pidFile, []byte(strconv.Itoa(cmd.Process.Pid)), 0o644)
185			if err != nil {
186				slog.Warn("failed to write pid file", "file", pidFile, "err", err)
187			}
188	
189			if err = cmd.Wait(); err != nil && !errors.Is(err, context.Canceled) {
190				var exitErr *exec.ExitError
191				if errors.As(err, &exitErr) && exitErr.ExitCode() == 1 && !s.dev && !reaped {
192					reaped = true
193					// This could be a port conflict, try to kill any existing ollama processes
194					if err := reapServers(); err != nil {
195						slog.Warn("failed to stop existing ollama server", "err", err)
196					} else {
197						slog.Debug("conflicting server stopped, waiting for port to be released")
198						continue
199					}
200				}
201				slog.Error("ollama exited", "err", err)
202			}
203		}
204		return ctx.Err()
205	}
