207	func (s *Server) cmd(ctx context.Context) (*exec.Cmd, error) {
208		settings, err := s.store.Settings()
209		if err != nil {
210			return nil, err
211		}
212	
213		cloudDisabled, err := s.store.CloudDisabled()
214		if err != nil {
215			return nil, err
216		}
217	
218		cmd := commandContext(ctx, s.bin, "serve")
219		cmd.Stdout, cmd.Stderr = s.log, s.log
220	
221		// Copy and mutate the environment to merge in settings the user has specified without dups
222		env := map[string]string{}
223		for _, kv := range os.Environ() {
224			s := strings.SplitN(kv, "=", 2)
225			env[s[0]] = s[1]
226		}
227		if settings.Expose {
228			env["OLLAMA_HOST"] = "0.0.0.0"
229		}
230		if settings.Browser {
231			env["OLLAMA_ORIGINS"] = "*"
232		}
233		if settings.Models != "" {
234			if _, err := os.Stat(settings.Models); err == nil {
235				env["OLLAMA_MODELS"] = settings.Models
236			} else {
237				slog.Warn("models path not accessible, using default", "path", settings.Models, "err", err)
238			}
239		}
240		if settings.ContextLength > 0 {
241			env["OLLAMA_CONTEXT_LENGTH"] = strconv.Itoa(settings.ContextLength)
242		}
243		if cloudDisabled {
244			env["OLLAMA_NO_CLOUD"] = "1"
245		} else {
246			env["OLLAMA_NO_CLOUD"] = "0"
247		}
248		cmd.Env = []string{}
249		for k, v := range env {
250			cmd.Env = append(cmd.Env, k+"="+v)
251		}
252	
253		cmd.Cancel = func() error {
254			if cmd.Process == nil {
255				return nil
256			}
257			return stop(cmd.Process)
258		}
259	
260		return cmd, nil
261	}
