278	// Attempt to retrieve inference compute information from the server
279	// log.  Set ctx to timeout to control how long to wait for the logs to appear
280	func GetInferenceInfo(ctx context.Context) (*InferenceInfo, error) {
281		info := &InferenceInfo{}
282		computeMarker := regexp.MustCompile(`inference compute.*library=`)
283		defaultCtxMarker := regexp.MustCompile(`vram-based default context`)
284		defaultCtxRegex := regexp.MustCompile(`default_num_ctx=(\d+)`)
285	
286		q := `inference compute.*%s=["]([^"]*)["]`
287		nq := `inference compute.*%s=(\S+)\s`
288		type regex struct {
289			q  *regexp.Regexp
290			nq *regexp.Regexp
291		}
292		regexes := map[string]regex{
293			"library": {
294				q:  regexp.MustCompile(fmt.Sprintf(q, "library")),
295				nq: regexp.MustCompile(fmt.Sprintf(nq, "library")),
296			},
297			"variant": {
298				q:  regexp.MustCompile(fmt.Sprintf(q, "variant")),
299				nq: regexp.MustCompile(fmt.Sprintf(nq, "variant")),
300			},
301			"compute": {
302				q:  regexp.MustCompile(fmt.Sprintf(q, "compute")),
303				nq: regexp.MustCompile(fmt.Sprintf(nq, "compute")),
304			},
305			"driver": {
306				q:  regexp.MustCompile(fmt.Sprintf(q, "driver")),
307				nq: regexp.MustCompile(fmt.Sprintf(nq, "driver")),
308			},
309			"name": {
310				q:  regexp.MustCompile(fmt.Sprintf(q, "name")),
311				nq: regexp.MustCompile(fmt.Sprintf(nq, "name")),
312			},
313			"total": {
314				q:  regexp.MustCompile(fmt.Sprintf(q, "total")),
315				nq: regexp.MustCompile(fmt.Sprintf(nq, "total")),
316			},
317		}
318		get := func(field, line string) string {
319			regex, ok := regexes[field]
320			if !ok {
321				slog.Warn("missing field", "field", field)
322				return ""
323			}
324			match := regex.q.FindStringSubmatch(line)
325	
326			if len(match) > 1 {
327				return match[1]
328			}
329			match = regex.nq.FindStringSubmatch(line)
330			if len(match) > 1 {
331				return match[1]
332			}
333			return ""
334		}
335		for {
336			select {
337			case <-ctx.Done():
338				return nil, fmt.Errorf("timeout scanning server log for inference compute details")
339			default:
340			}
341			file, err := os.Open(serverLogPath)
342			if err != nil {
343				slog.Debug("failed to open server log", "log", serverLogPath, "error", err)
344				time.Sleep(time.Second)
345				continue
346			}
347			defer file.Close()
348			scanner := bufio.NewScanner(file)
349			for scanner.Scan() {
350				line := scanner.Text()
351				// Check for inference compute lines
352				if computeMarker.MatchString(line) {
353					ic := InferenceCompute{
354						Library: get("library", line),
355						Variant: get("variant", line),
356						Compute: get("compute", line),
357						Driver:  get("driver", line),
358						Name:    get("name", line),
359						VRAM:    get("total", line),
360					}
361	
362					slog.Info("Matched", "inference compute", ic)
363					info.Computes = append(info.Computes, ic)
364					continue
365				}
366				// Check for default context length line
367				if defaultCtxMarker.MatchString(line) {
368					match := defaultCtxRegex.FindStringSubmatch(line)
369					if len(match) > 1 {
370						numCtx, err := strconv.Atoi(match[1])
371						if err == nil {
372							info.DefaultContextLength = numCtx
373							slog.Info("Matched default context length", "default_num_ctx", numCtx)
374						}
375					}
376					return info, nil
377				}
378				// If we've found compute info but hit a non-matching line, return what we have
379				// This handles older server versions that don't log the default context line
380				if len(info.Computes) > 0 {
381					return info, nil
382				}
383			}
384			time.Sleep(100 * time.Millisecond)
385		}
386	}
