2052			modelName, err := deps.resolveRunModel(cmd.Context(), action.RunModelRequest())
2053			if errors.Is(err, launch.ErrCancelled) {
2054				return true, nil
2055			}
2056			if err != nil {
2057				return true, fmt.Errorf("selecting model: %w", err)
2058			}
2059			if err := deps.runModel(cmd, modelName); err != nil {
2060				return true, err
2061			}
2062			return true, nil
2063		case tui.TUIActionLaunchIntegration:
2064			saveLauncherSelection(action)
2065			err := deps.launchIntegration(cmd.Context(), action.IntegrationLaunchRequest())
2066			if errors.Is(err, launch.ErrCancelled) {
2067				return true, nil
2068			}
2069			if err != nil {
2070				return true, fmt.Errorf("launching %s: %w", action.Integration, err)
2071			}
2072			// VS Code is a GUI app — exit the TUI loop after launching
2073			if action.Integration == "vscode" {
2074				return false, nil
2075			}
2076			return true, nil
2077		default:
2078			return false, fmt.Errorf("unknown launcher action: %d", action.Kind)
2079		}
